var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 근방에 역병의 악취가 짙도다. 악단이 남긴 자취로구나.","JPN":"この辺りは疫病の悪臭がひどい。楽団が残したものであろう。","ENG":"The stench of the plague is thick around here. It must be traces left behind by the Orchestra.","TWN":"樂團來過這裡，這一帶有很濃厚的瘟疫惡臭。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"악단이라고요?","JPN":"楽団？","ENG":"Orchestra?","TWN":"樂團？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그, 그렇다면 엘리시움 필하모닉이 여기 와 있다는 거예요? 네퀴티아도?","JPN":"じゃ、じゃあ、エリシウムフィルハーモニーがここに来てるってことですか？　ネキティアも？","ENG":"A-are you saying that Elysium Philharmonic is here? And even Nequitia?","TWN":"難道是愛樂組織來過？莉奎蒂亞也在？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네퀴티아의 기척에 비할 바는 아니다.","JPN":"ネキティアの気配とは比べものになるまい。","ENG":"It is nothing compared to Nequitia's presence.","TWN":"這不是莉奎蒂亞的味道。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하나는 미약하고 다른 하나는 쇠약하였으니, 이는 최고 단원들의 것이로다.","JPN":"一つは微弱であり、もう一つは衰弱している。これは首席奏者たちのものだ。","ENG":"One is weak and the other has withered. They must be of the Elite Members.","TWN":"其中一個氣息微弱，而另一個氣息衰弱。看來是首席樂手。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그러니 두려워하지 말라, 병사여.","JPN":"ゆえに、恐れるな。兵士よ。","ENG":"But do not be afraid, soldier.","TWN":"所以你不用害怕，士兵。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 두, 두려워하는 건…. 딱히…….","JPN":"いいえ。べ、別に……怖がってるわけでは……","ENG":"No. I-I'm not afraid... Not really...","TWN":"不，我…我才沒有害怕……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님? 괜찮으십니까?","JPN":"副戦隊長殿？　大丈夫ですか？","ENG":"Deputy Commander? Are you okay?","TWN":"副戰隊長？你沒事吧？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mh?","TWN":"嗯？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아니야. 아무것도. 왜 그러니?","JPN":"いいえ。何でもないわ。どうかした？","ENG":"No, it's nothing. What is it?","TWN":"不，沒什麼。怎麼了？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"필그림 측 병사들의 시신을 찾았습니다.","JPN":"ピルグリム側の兵士の死体を発見しました。","ENG":"We found Pilgrim soldier corpses.","TWN":"我們找到了朝聖者士兵的屍體。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"보초를 서던 모양인데 셋 다 4번 경추를 꿰뚫렸습니다.","JPN":"見張りをしていたようですが、全員、頸椎を貫通されています。","ENG":"It looked like they were guarding the post, but all three had their 4th vertebrae pierced.","TWN":"似乎是哨兵，三個都被打穿第四節頸椎。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"익숙한 솜씨네. 다른 외상은?","JPN":"手慣れてるね。他に外傷は？","ENG":"Sounds familiar. Any other trauma?","TWN":"熟悉的手法。有沒有別的外傷？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전혀 없습니다.","JPN":"ありません。","ENG":"No, ma'am.","TWN":"完全沒有。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 그리고 쓰러진 형태를 봐선….","JPN":"そう。それに、倒れている状態からして……","ENG":"Okay. Judging from how they collapsed...","TWN":"好，從他們倒下的形態來看……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"상대가 접근한 걸 알아채자마자 거의 동시에 당했으려나.","JPN":"相手が接近したことに気付いたのとほぼ同時にやられたのかな。","ENG":"They seemed to have dropped dead as soon as they noticed the enemy approaching.","TWN":"應該是剛發現對方靠近就被遭到毒手。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"셰나로군요. 저희보다 한 발 앞서 온 모양입니다.","JPN":"シェナですね。私たちが一歩遅かったようです。","ENG":"It's Shena. Looks like she is one step ahead of us.","TWN":"是世娜，看來她比我們快一步。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이전에 입은 부상을 회복하지 못했다고 하더니 잘만 휘젓고 다니는군요.","JPN":"この前の怪我が回復していないと言っていましたが、それほどでもないようですね。","ENG":"You said she has not fully recovered from her last injury, but she seems to be well enough to cause trouble like this.","TWN":"世娜不是還沒有完全恢復嗎？怎麼感覺她充滿幹勁。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"어떻게 된 겁니까, 길고양이?","JPN":"どういうことですか？　野良猫。","ENG":"What is the meaning of this, Stray Cat?","TWN":"這是怎麼回事，流浪貓？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흥. 내가 셰나 일정까지 챙겨야 돼?","JPN":"ふん。私がシェナのスケジュールまで管理してると思う？","ENG":"Hmph. You expect me to keep track of Shena's schedule too?","TWN":"哼，我怎麼可能知道她的行程？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"짐작 가는 것이라도 말해 주는 것이 어떤가.","JPN":"心当たりでもいいから言った方が身のためだ。","ENG":"How about telling us even if it is just a guess?","TWN":"至少可以跟我們講一講你的猜測吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우리가 서로의 입장을 이해해 줄 만큼 원만한 관계도 아니지 않았나?","JPN":"互いの立場を察し合うほど我々は友好的な関係ではないだろう？","ENG":"After all, we are not in good enough terms to understand each other's position, no?","TWN":"我們的關係似乎還沒有好到要顧慮對方的立場吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kgh...","TWN":"哼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님은 내가 못미더우셨겠지. 그래서 보험 삼아 셰나를 보내셨을 거야.","JPN":"マエストロは私のことが信頼できなかったのよ。だから保険にシェナを送ったんでしょうね。","ENG":"My guess is that the Chief Conductor didn't trust me enough. That's why she sent Shena as her safety net.","TWN":"指揮家應該是不怎麼信任我，以防萬一才派出世娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하는 짓을 보면 못미덥기는 하겠어요. 가축 취급까지 했잖아요.","JPN":"そりゃあ、信じられないはずですよ。家畜扱いまでしてたじゃないですか。","ENG":"Seeing how you act, I can see why she wouldn't trust you. You treated her like a pet.","TWN":"你確實不怎麼可靠，還把人家當寵物對待。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"조용히 있지 그래? 중사님은 나한테 붙잡혔으면 영원히 캐스터네츠만 쳤어.","JPN":"黙っててくれない？　軍曹さんは私に捕まってたら、一生カスタネットを叩いてたわ。","ENG":"Oh, shush, will you? If I had caught you, Sergeant, you'd be playing the castanets forever.","TWN":"你最好閉嘴。要是你落入我手中，我讓你一輩子都只能打響板。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"벌써 협박할 여유까지 생겼어? 슬슬 해치워 버리는 편이 나으려나.","JPN":"もう脅す余裕まであるの？　そろそろ消滅させた方がいいのかしら。","ENG":"You already feel comfortable enough to threaten us? Guess it's time we got rid of you now then, huh?","TWN":"竟然還敢威脅我們？果然還是應該除掉你嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 말, 누가 들으면 저희가 악당인 줄 오해하겠어요.","JPN":"その言葉、一歩間違えばこっちが悪党だって誤解されますよ。","ENG":"You know, people would think we're the villains if they heard that out of context.","TWN":"別人要是聽見這話，一定會以為我們才是壞人。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"우리는 전쟁을 하고 있는 중이야, 중사님.","JPN":"私たちは戦争中なの、軍曹。","ENG":"We are at war right now, Sergeant.","TWN":"我們正在經歷戰爭，中士。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"조금은 독해져야 할 필요도 있지 않을까?","JPN":"時には強く出る必要もあるでしょう？","ENG":"Don't you think it's time you became cold-blooded?","TWN":"不應該變得更心狠手辣一些嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아무리 약해졌어도 셰나는 골치 아픈 상대야.","JPN":"弱くなったとはいえ、シェナは厄介な相手よ。","ENG":"Although she might have gotten weak, Shena is still a force to be reckoned with.","TWN":"世娜雖然變弱，但仍然很棘手。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니까…. 이 기회에 끝을 내자.","JPN":"だから……この際に終わりにしましょう。","ENG":"That's why... we should end her while we have the chance.","TWN":"所以…趁這個機會做個了結吧。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};